### 1. MockDoverStageDriver
```rust
pub struct MockDoverStageDriver {
    position: AtomicF64,
    velocity: f64,
    acceleration: f64,
    top_enabled: AtomicBool,
    top_config: Option<TopConfig>,
}

impl Movable for MockDoverStageDriver {
    async fn move_abs(&mut self, position: f64) -> Result<()> {
        // Simulate motion time based on velocity
        let distance = (position - self.position.load()).abs();
        let time = distance / self.velocity;
        tokio::time::sleep(Duration::from_secs_f64(time)).await;
        self.position.store(position);
        Ok(())
    }
}

impl TriggerOnPosition for MockDoverStageDriver {
    async fn enable_top(&mut self, start: f64, end: f64, increment: f64, bidir: bool, pulse_ns: u64) -> Result<()> {
        self.top_config = Some(TopConfig { start, end, increment, bidir, pulse_ns });
        self.top_enabled.store(true);
        Ok(())
    }
}
```

### 2. MockAndorCameraDriver
```rust
pub struct MockAndorCameraDriver {
    width: usize,          // 2560
    height: usize,         // 1 (binned for spectroscopy)
    gate_mode: GateMode,
    ddg_delay_ps: u64,
    ddg_width_ps: u64,
    mcp_gain: u16,
    temperature: f64,
}

impl FrameProducer for MockAndorCameraDriver {
    async fn acquire_frame(&mut self) -> Result<Frame> {
        // Generate synthetic spectrum with emission lines
        let spectrum = generate_synthetic_libs_spectrum(
            self.ddg_delay_ps,
            self.mcp_gain,
        );
        Ok(Frame { data: spectrum, timestamp: Instant::now() })
    }
}

fn generate_synthetic_libs_spectrum(delay_ps: u64, mcp_gain: u16) -> Vec<f64> {
    // Generate realistic LIBS spectrum with:
    // - Continuum background (decays with delay)
    // - Emission lines (element-dependent)
    // - Noise (proportional to MCP gain)
    let mut spectrum = vec![0.0; 2560];

    // Continuum: exponential decay with delay
    let continuum = 1000.0 * (-delay_ps as f64 / 1e6).exp();

    // Add emission lines at known positions
    add_emission_line(&mut spectrum, 310.0, 5000.0);  // Al I
    add_emission_line(&mut spectrum, 394.4, 3000.0);  // Al I
    add_emission_line(&mut spectrum, 396.2, 2500.0);  // Al I

    // Add noise
    add_gaussian_noise(&mut spectrum, (mcp_gain as f64 / 4095.0) * 100.0);

    spectrum
}
```

