## Rust Implementation
```rust
// common/src/processing/radiance_calibration.rs

pub struct RadianceCalibrator {
    lamp_spectrum: LampSpectrum,
    grating_calibrations: HashMap<u8, CalibrationSpectrum>,
}

impl RadianceCalibrator {
    pub fn new(lamp_file: &Path, cal_files: &[(u8, &Path)]) -> Result<Self>;

    pub fn calibrate(
        &self,
        spectrum: &Spectrum,
        grating: u8,
        normalize: bool,
    ) -> Result<Spectrum> {
        let cal = self.grating_calibrations.get(&grating)
            .ok_or_else(|| anyhow\!("No calibration for grating {}", grating))?;

        // Interpolate calibration to match spectrum wavelengths
        let cal_interp = interp1d(&cal.wavelengths, &cal.values, &spectrum.wavelengths)?;
        let lamp_interp = interp1d(
            &self.lamp_spectrum.wavelengths,
            &self.lamp_spectrum.values,
            &spectrum.wavelengths
        )?;

        // Correction factor: lamp / measured_calibration
        let correction: Vec<f64> = lamp_interp.iter()
            .zip(cal_interp.iter())
            .map(|(l, c)| l / c)
            .collect();

        // Apply correction
        let calibrated: Vec<f64> = spectrum.values.iter()
            .zip(correction.iter())
            .map(|(s, c)| s * c)
            .collect();

        let mut result = Spectrum {
            wavelengths: spectrum.wavelengths.clone(),
            values: calibrated,
        };

        if normalize {
            let max = result.values.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
            result.values.iter_mut().for_each(|v| *v /= max);
        }

        Ok(result)
    }
}
```

